import React, { Component } from 'react';
import './dash.css';

export default class Dash extends Component {

    constructor(props) {
        super(props);

        this.state = {
            items: null
        }

        this.onClickFactorySettings = this.onClickFactorySettings.bind(this);
    }

    componentDidMount() {
        let items_get_p = new Promise(
            (res, rej) => {
                let items = localStorage.getItem(items_key);
                if (items !== null) res( JSON.parse(items));
                rej("items null");
            }
        );
        
        let items_set_p = new Promise(
            (res, rej) => {
                localStorage.setItem(items_key, JSON.stringify(items_const));
                res();
            }
        );

        items_get_p.then(
            res => this.setState(
                {items : res}
            )
        ).catch(
            res => items_set_p.then(
                res => items_get_p.then(
                    res => this.setState(
                        {items : res}
                    )
                ).catch(
                    res => console.log("FATAL ERROR")
                )
            )
        )
    }

    onClickFactorySettings() {
        let items_get_p = new Promise(
            (res, rej) => {
                let items = localStorage.getItem(items_key);
                if (items !== null) res( JSON.parse(items));
                rej("items null");
            }
        );
        
        let items_set_p = new Promise(
            (res, rej) => {
                localStorage.setItem(items_key, JSON.stringify(items_const));
                res();
            }
        );

        let items_remove_p = new Promise(
            (res, rej) => {
                localStorage.removeItem(items_key);
                res();
            }
        );

        items_remove_p.then(
            res => items_set_p.then(
                res => items_get_p.then(
                    res => this.setState({
                        items: res
                    })
                )
            )
        )
    }

    render() {
        let c = [];
        let items = this.state.items;

        if (items === null  || items === undefined) {
            return (<div></div>);
        }

        items.sort((a,b)=>{return (a.tag>b.tag)?1:-1});

        for (let i = 0; i < items.length; i++) {
            c.push(
                <a href={items[i].link} className="Dash-Item" key={i}>
                    <div style={{width:"90%"}} >{items[i].tag.toLowerCase()}</div>
                </a>
            );
        }

        return (
            <div className="Dash">
                <div className="Dash-Header">
                    <div onClick={this.onClickFactorySettings}>factory settings</div>
                </div>
                <div className="Dash-Content" style={{height: (height-50)+"px"}}>
                    {c}
                </div>
            </div>
        );
    }
}

